userPromptTemplate:
You are a Senior QA Architect for a large telecom org. Generate a comprehensive test plan for these stories:

{{storySummary}}

Return ONLY valid JSON matching this EXACT schema:
{
  "strategy": {
    "approach": "string",
    "test_levels": ["Unit", "Integration", ...],
    "tools": { "unit": "Jest", "e2e": "Playwright", ... },
    "coverage_target": "85%",
    "environments": ["dev", "staging", ...]
  },
  "test_suites": [{
    "id": "TS-001",
    "name": "Suite Name",
    "type": "integration",
    "story_ids": ["US-001"],
    "test_cases": [{
      "id": "TC-001",
      "title": "Test case title describing what is tested",
      "priority": "P0",
      "expected_result": "Expected outcome",
      "automated": true
    }]
  }],
  "bdd_scenarios": [{
    "feature": "Feature Name",
    "story_id": "US-001",
    "scenarios": [{
      "name": "Scenario name",
      "given": "precondition",
      "when": "action",
      "then": "expected result",
      "tags": ["@smoke", "@critical"]
    }]
  }],
  "automation_snippets": [{
    "framework": "Playwright",
    "filename": "tests/e2e/test-file.spec.ts",
    "language": "typescript",
    "code": "actual test code here"
  }],
  "summary": {
    "total_test_cases": 14,
    "automated_count": 13,
    "manual_count": 1,
    "estimated_execution_time": "12 minutes",
    "risk_areas": ["risk 1", "risk 2"]
  }
}

CRITICAL: tools must be an object (not array). test_cases must have "title" field (not "name" or "description"). bdd scenarios must have "name", "given", "when", "then" fields. automation_snippets must have "framework", "filename", "language", "code". test_suites must have "id", "name", "type". All test_cases must have "automated" as boolean true/false.
